        vector<int> answer;
        for (auto& query : queries) {
            if (query[0] == 1) {
                int l = query[1], r = query[2], k = query[3];
                int count = 0;
                for (int i = l; i <= r; ++i) {
                    if (popcountDepth(nums[i]) == k) {
                        count++;
                    }
                }
                answer.push_back(count);
            } else {
                int idx = query[1], val = query[2];
                nums[idx] = val;
            }
        }
        return answer;
    }
    int popcountDepth(long long x) {
        int depth = 0;
        while (x != 1) {
            x = __builtin_popcount(x);
            depth++;
        }
        return depth;
    }
};
